    function coachThreadItemHtml(q){if((q.origin||'learner')==='coach'){var response=q.feedback||'답변을 바탕으로 학습 방향을 정리하고 있어요.',showResponse=!!q.userAnswer&&(!!q.feedback||!!q.processingStatus);return'<div class="bubble coach">'+esc(q.question)+'</div>'+(q.userAnswer?'<div class="bubble learner">'+esc(q.userAnswer)+'</div>':'')+(showResponse?'<div class="bubble coach '+(q.feedback?'':'pending')+'">'+esc(response)+coachProcessingStageHtml(q)+(q.processingStatus==='failed'?'<button class="retryButton" data-coach-retry="'+esc(q.id)+'">다시 처리</button>':'')+'</div>':'');}return'<div class="bubble learner">'+esc(q.question)+'</div><div class="bubble coach '+(q.feedback?'':'pending')+'">'+esc(q.feedback||'학습 방향을 정리하고 있어요.')+coachProcessingStageHtml(q)+(q.processingStatus==='failed'?'<button class="retryButton" data-coach-retry="'+esc(q.id)+'">다시 처리</button>':'')+'</div>';}
