    function renderStatus(){var previousInput=document.getElementById('coachInput');if(previousInput&&lastCoachDraftKey)coachDrafts[lastCoachDraftKey]=previousInput.value;var nodes=(state.nodes||[]).filter(function(n){return n.type!=='root';}),understoodNodes=nodes.filter(function(n){return n.status==='understood';}),gapNodes=nodes.filter(function(n){return n.status==='confused'||n.status==='review';}),understood=understoodNodes.length,percent=nodes.length?Math.round(understood/nodes.length*100):0,recommended=nodeById(state.recommendedNodeId),coachItems=(state.questions||[]).filter(function(q){return q.scope==='coach';}),openCoach=coachItems.slice().reverse().find(function(q){return(q.origin||'learner')==='coach'&&q.status==='open'&&!q.userAnswer;}),contentQuestions=(state.questions||[]).filter(function(q){return q.scope!=='coach';}),unresolved=contentQuestions.filter(function(q){return q.status==='open'||q.status==='review'||q.processingStatus==='failed'||q.processingStatus==='queued'||q.processingStatus==='running'||q.processingStatus==='merging';});var draftKey=openCoach?'answer:'+openCoach.id:'ask';lastCoachDraftKey=draftKey;var html='<div class="callout info"><b>학습 내용이 아니라 학습 방향을 묻는 곳</b><p>오른쪽 대화는 선택한 내용과 노트를 다듬고, 여기서는 내가 무엇을 이해했고 다음에 무엇을 공부할지 조정합니다.</p></div><div class="card"><h2>'+percent+'% 이해 확인</h2><div class="progressTrack"><div class="progressFill" style="width:'+percent+'%"></div></div><p class="small">개념 '+nodes.length+' · 해결할 질문 '+unresolved.length+' · 복습 항목 '+gapNodes.length+'</p></div>'+(recommended?'<div class="card recommendedCard"><h2>다음 추천</h2><b>'+esc(recommended.label)+'</b><p class="small">'+esc(recommended.summary||'이 개념을 다음 순서로 살펴보세요.')+'</p></div>':'')+'<div class="card"><h2>학습 목표</h2><ul class="noteList">'+(state.goals||[]).map(function(g){return'<li>'+esc(g)+'</li>';}).join('')+'</ul></div><div class="statusColumns"><div class="card"><h3>이해함</h3>'+nodeStatusList(understoodNodes)+'</div><div class="card"><h3>헷갈림·복습</h3>'+nodeStatusList(gapNodes)+'</div></div>'+(state.followups&&state.followups.length?'<div class="card"><h2>다음 행동</h2><ul class="statusList">'+state.followups.map(function(item){return'<li>'+esc(item)+'</li>';}).join('')+'</ul></div>':'')+'<div class="card"><h2>코치와 방향 조정</h2><p class="small">목표를 바꾸거나, 빈틈·다음 순서·복습 질문을 요청하세요.</p><div class="coachPrompts"><button data-coach-prompt="현재 이해의 빈틈을 찾아줘.">빈틈 찾기</button><button data-coach-prompt="다음 학습 순서를 추천해줘.">다음 순서</button><button data-coach-prompt="코드보다 전체 구조 이해를 우선해줘.">구조 우선</button><button data-coach-prompt="지금 이해했는지 확인할 질문을 하나 내줘.">복습 질문</button></div><div class="coachThread">'+(coachItems.length?coachItems.map(coachThreadItemHtml).join(''):'<p class="small">아직 학습 방향 대화가 없습니다.</p>')+'</div><div class="detailSection"><textarea id="coachInput" placeholder="'+(openCoach?'내 말로 답해보세요.':'예: Bridge보다 RN lifecycle을 먼저 공부하고 싶어.')+'"></textarea><div class="row" style="margin-top:8px"><button id="coachSend" class="primary" data-mode="'+(openCoach?'answer':'ask')+'" data-question-id="'+esc(openCoach&&openCoach.id||'')+'">'+(openCoach?'코치 질문에 답하기':'방향 조정하기')+'</button><span id="coachStatus" class="small"></span></div></div></div>';document.getElementById('statusBody').innerHTML=html;var draftInput=document.getElementById('coachInput');draftInput.value=coachDrafts[draftKey]||'';draftInput.addEventListener('input',function(){coachDrafts[draftKey]=draftInput.value;});document.querySelectorAll('[data-coach-prompt]').forEach(function(button){button.addEventListener('click',function(){var input=document.getElementById('coachInput');input.value=button.dataset.coachPrompt;coachDrafts[draftKey]=input.value;input.focus();});});document.querySelectorAll('[data-coach-retry]').forEach(function(button){button.addEventListener('click',function(){button.disabled=true;post('/coach/retry',{questionId:button.dataset.coachRetry}).catch(function(error){window.alert('학습 코치를 다시 실행하지 못했습니다: '+error.message);}).finally(function(){button.disabled=false;});});});document.getElementById('coachSend').addEventListener('click',function(){var input=document.getElementById('coachInput'),button=document.getElementById('coachSend'),status=document.getElementById('coachStatus'),message=input.value.trim(),answering=button.dataset.mode==='answer';if(!message)return;button.disabled=true;status.textContent='코치에게 전달 중...';post(answering?'/coach/answer':'/coach',answering?{questionId:button.dataset.questionId,answer:message}:{message:message}).then(function(){coachDrafts[draftKey]='';input.value='';status.textContent='학습 방향을 정리하고 있어요.';}).catch(function(error){status.textContent='실패: '+error.message;}).finally(function(){button.disabled=false;});});}
    function render(){if(!state)return;document.getElementById('title').textContent=state.title||'Study Hard';document.getElementById('meta').innerHTML=(state.sourceTitle?esc(state.sourceTitle)+' · ':'')+'revision '+esc(state.revision||0)+' · '+esc(boardCards().length)+' cards';setSurface(state.activeSurface||'note',false);renderBreadcrumb();renderMap();renderFlow();renderNote();renderDetail();renderStatus();window.__studyHardDebug={state:function(){return state;},boardCards:boardCards,flowNodes:toFlowNodes,flowEdges:toFlowEdges,sequenceSource:sequenceSource,errors:window.__studyHardErrors};}
    document.getElementById('historyPreviewClose').addEventListener('click',closeHistoryPreview);document.getElementById('historyRestoreCancel').addEventListener('click',function(){resolveHistoryRestore(false);});document.getElementById('historyRestoreAccept').addEventListener('click',function(){resolveHistoryRestore(true);});document.getElementById('historyRestoreConfirm').addEventListener('click',function(event){if(event.target===event.currentTarget)resolveHistoryRestore(false);});document.addEventListener('keydown',function(event){if(event.key!=='Escape')return;var confirm=document.getElementById('historyRestoreConfirm'),preview=document.getElementById('historyPreviewOverlay');if(!confirm.hidden){resolveHistoryRestore(false);return;}if(!preview.hidden)closeHistoryPreview();});
    document.getElementById('htmlExportButton').addEventListener('click',exportHtml);document.getElementById('notionExportButton').addEventListener('click',exportNotion);document.getElementById('historyButton').addEventListener('click',openHistory);document.querySelectorAll('[data-surface]').forEach(function(b){b.addEventListener('click',function(){setSurface(b.dataset.surface,true);});});document.querySelectorAll('[data-close]').forEach(function(b){b.addEventListener('click',function(){closeDrawer(b.dataset.close);});});['statusButton','flowStatusButton','noteStatusButton'].forEach(function(id){var button=document.getElementById(id);if(button)button.addEventListener('click',function(){closeDrawer('historyDrawer');openDrawer('statusDrawer');});});['detailButton','flowDetailButton','noteDetailButton'].forEach(function(id){var button=document.getElementById(id);if(button)button.addEventListener('click',function(){renderDetail();openDrawer('detailDrawer');});});document.getElementById('newMemoButton').addEventListener('click',function(){var text=window.prompt('질문·깨달음·코드 메모를 적어주세요.');if(!text||!text.trim())return;post('/memo',{text:text.trim()}).then(function(){setSurface('map',false);setTimeout(fitAll,100);}).catch(function(error){window.alert('메모를 만들지 못했습니다: '+error.message);});});document.getElementById('fitButton').addEventListener('click',fitAll);document.getElementById('relayoutButton').addEventListener('click',function(){post('/relayout').then(function(){initialViewportApplied=false;setTimeout(fitAll,80);});});async function load(){state=await fetch('/state').then(function(r){return r.json();});render();}load();var events=new EventSource('/events');events.onmessage=function(event){state=JSON.parse(event.data);render();};
